    and c.status = #{status}

order by c.status asc, c.id desc



    c.is_deleted = #{isDeleted}
    and (c.lname is null or c.lname not like '%斜井%')
    and c.lname = #{lname}
    and c.company like concat('%', #{company}, '%')
    and c.tname = #{tname}

order by c.px asc, c.id desc

select c.id, c.lname, c.company, c.channel, c.shitype, c.status from a_camera c
c.is_deleted = #{isDeleted} and c.lname like concat('%', #{lname}, '%') and c.company like concat('%', #{company}, '%') and c.status = #{status}
order by c.px asc, c.id desc

select count(1)
from a_camera
where is_deleted = '0'
  and carmip = #{carmip}
  and id != #{id}

select dict_label
from sys_dict_data
where dict_type = #{dictType}
  and dict_value = #{dictValue}
  and status = '0'
limit 1
